tests:
def test_cycle_detected():
    g = Graph()
    g.add_node(Node('a', dependencies=['b']))
    g.add_node(Node('b', dependencies=['a']))
    try:
        g.resolve()
        assert False
    except CycleError:
        pass

def test_self_loop_cycle():
    g = Graph()
    g.add_node(Node('a', dependencies=['a']))
    try:
        g.resolve()
        assert False
    except CycleError:
        pass
